sql:
SELECT title
FROM external_courses
WHERE credit_points > (SELECT AVG(credit_points) FROM external_courses);

SELECT COUNT(*) 
FROM courses 
WHERE program_id = (SELECT program_id FROM students WHERE first_name = 'Bob' AND last_name = 'Smith');

external_knowledge:
- 'Shining stars sailing the farthest in the sea of knowledge' refers to the students who have accumulated the highest credit points by completing their courses;
- Ranking is determined by the total credit points, with the highest credit points ranking first;
- The query focuses on students with the status 'completed', meaning they have finished their courses.

sql:
SELECT semester, COUNT(course_id) AS course_count
FROM courses
GROUP BY semester;

SELECT title
FROM courses
WHERE course_id = 1;

SELECT AVG(credit_points) AS average_credit_points
FROM courses
WHERE semester = 'Fall';
